import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue.ktlint_official
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.BeforeEach
import org.junit.jupiter.api.Test

internal class IndentationRuleClassHeaderRegressionTest {
    @BeforeEach
    internal fun setUp() {
        System.setProperty("KTLINT_UNIT_TEST_TRACE", "off")
    }

    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a class with multiline super type list but without explicit constructor then class body should not be indented`() {
        val code =
            """
            class Foo(
                val bar1: Bar,
                val bar2: Bar,
            ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                // body
            }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
            .isFormattedAs(code)
    }

    @Test
    fun `Given a class with explicit constructor and multiline super type list then class body should not be indented and super types should be aligned`() {
        val code =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                BarFoo1,
                BarFoo2 {
                    // body
                }
            """.trimIndent()

        val formattedCode =
            """
            class Foo
                constructor(
                    val bar1: Bar,
                    val bar2: Bar,
                ) : FooBar(bar1, bar2),
                    BarFoo1,
                    BarFoo2 {
                    // body
                }
            """.trimIndent()

        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .isFormattedAs(formattedCode)
    }
}
"}

